// Parse URL to extract maincat, category, filters and build Product Search API URL
// Based on scraper_service.py:parse_beslist_url() and build_api_params()

const url = ($json.url || '').split('?')[0];

// Maincat name -> API ID mapping (from scraper_service.py MAIN_CATEGORY_IDS)
const MAIN_CATEGORY_IDS = {
  'autos': 37000, 'baby_peuter': 8, 'boeken': 701,
  'cadeaus_gadgets_culinair': 262, 'computers': 6, 'dieren_accessoires': 34000,
  'gezond_mooi': 286, 'elektronica': 655, 'voor_volwassenen': 452,
  'eten_drinken': 11, 'fietsen': 38000, 'films-series': 700,
  'cddvdrom': 4, 'horloge': 30000, 'huishoudelijke_apparatuur': 12000,
  'kantoorartikelen': 361, 'mode': 137, 'klussen': 35000,
  'meubilair': 10, 'mode_accessoires': 33000, 'accessoires': 40000,
  'muziekinstrument': 31000, 'parfum_aftershave': 29000, 'main_sanitair': 27000,
  'schoenen': 32000, 'sieraden_horloges': 347, 'software': 155,
  'speelgoed_spelletjes': 332, 'sport_outdoor_vrije-tijd': 206,
  'tuin_accessoires': 36000, 'huis_tuin': 165
};

// Remove domain if present
let path = url;
if (path.startsWith('http')) {
  path = '/' + path.split('/', 3).slice(3).join('/') || path.replace(/^https?:\/\/[^/]+/, '');
}
path = path.replace(/\/$/, '');

let maincat_name = null;
let category = null;
let filters = {};

// Pattern 1: /products/{maincat}/{category}/c/{filters}
let match = path.match(/^\/products\/([^/]+)\/([^/]+)\/c\/(.+)$/);
if (match) {
  maincat_name = match[1];
  category = match[2];
  const filterPairs = match[3].split('~~');
  for (const pair of filterPairs) {
    const idx = pair.indexOf('~');
    if (idx > 0) {
      const name = pair.substring(0, idx);
      const value = pair.substring(idx + 1);
      if (!filters[name]) filters[name] = [];
      filters[name].push(value);
    }
  }
}

// Pattern 2: /products/{maincat}/c/{filters}
if (!match) {
  match = path.match(/^\/products\/([^/]+)\/c\/(.+)$/);
  if (match) {
    maincat_name = match[1];
    const filterPairs = match[2].split('~~');
    for (const pair of filterPairs) {
      const idx = pair.indexOf('~');
      if (idx > 0) {
        const name = pair.substring(0, idx);
        const value = pair.substring(idx + 1);
        if (!filters[name]) filters[name] = [];
        filters[name].push(value);
      }
    }
  }
}

// Pattern 3: /products/{maincat}/{category}
if (!match) {
  match = path.match(/^\/products\/([^/]+)\/([^/]+)$/);
  if (match) {
    maincat_name = match[1];
    category = match[2];
  }
}

// Pattern 4: /products/{maincat}
if (!match) {
  match = path.match(/^\/products\/([^/]+)$/);
  if (match) {
    maincat_name = match[1];
  }
}

const maincat_id = MAIN_CATEGORY_IDS[maincat_name] || null;

if (!maincat_id) {
  return { json: { url, parse_success: false, api_url: '' } };
}

// Build API URL
const params = new URLSearchParams();
params.set('mainCategory', maincat_id.toString());
if (category) params.set('category', category);
params.set('sort', 'popularity');
params.set('sortDirection', 'desc');
params.set('limit', '76');
params.set('offset', '0');
params.set('isBot', 'false');
params.set('countryLanguage', 'nl-nl');
params.set('experiment', 'topProducts');
params.set('trackTotalHits', 'false');

for (const [filterName, values] of Object.entries(filters)) {
  for (let i = 0; i < values.length; i++) {
    params.set(`filters[${filterName}][${i}]`, values[i]);
  }
}

const api_url = `https://productsearch-v2.api.beslist.nl/search/products?${params.toString()}`;

return {
  json: {
    url,
    maincat_name,
    maincat_id,
    category: category || null,
    filters,
    parse_success: true,
    api_url
  }
};

// Extract products from Product Search API response
// Based on scraper_service.py:scrape_product_page_api() lines 534-558

const apiResponse = $json;
const parsedData = $('parse_url_and_build_api').item.json;
const url = parsedData.url;

// Extract selected facets for product subject
const facets = apiResponse.facets || [];
const selectedFacets = [];
for (const facetGroup of facets) {
  const facetName = facetGroup.name || '';
  const values = facetGroup.values || [];
  for (const value of values) {
    if (value.selected) {
      selectedFacets.push({
        facet_name: facetName,
        facet_value: value.facetValue || '',
        detail_value: value.detailValue || value.facetValue || ''
      });
    }
  }
}

// Get deepest category name
const apiProducts = apiResponse.products || [];
const categories = apiProducts.length > 0 ? (apiProducts[0].categories || []) : [];
const deepestCategoryName = categories.length > 0 ? categories[categories.length - 1].name || '' : '';

// Build product subject from selected facets
const colorFacets = ['kleur', 'kleurtint'];
const productNameFacets = ['serie', 'modelnaam', 'modelnaam_mob', 'model', 'type'];
const brandFacets = ['merk'];
const targetGroupFacets = ['doelgroep'];

let hasSpecificProduct = false;
const parts = [];
const colors = [];
const productNames = [];
const brands = [];
const targetGroups = [];
const other = [];

for (const facet of selectedFacets) {
  const nameLower = facet.facet_name.toLowerCase();
  if (colorFacets.some(c => nameLower.includes(c))) {
    colors.push(facet.detail_value);
  } else if (productNameFacets.some(p => nameLower.includes(p))) {
    productNames.push(facet.detail_value);
    hasSpecificProduct = true;
  } else if (brandFacets.some(b => nameLower.includes(b))) {
    brands.push(facet.detail_value);
  } else if (targetGroupFacets.some(t => nameLower.includes(t))) {
    targetGroups.push(facet.detail_value);
  } else {
    other.push(facet.detail_value);
  }
}

const subjectParts = [...colors, ...productNames, ...brands, ...targetGroups, ...other];
if (!hasSpecificProduct && deepestCategoryName && subjectParts.length > 0) {
  subjectParts.push(deepestCategoryName.toLowerCase());
}
const productSubject = subjectParts.join(' ');
const h1_title = productSubject || deepestCategoryName || parsedData.maincat_name || 'Unknown';

// Extract products (max 30, shopCount >= 2, skip orResult)
const products = [];
for (const product of apiProducts.slice(0, 70)) {
  if (product.type === 'orResult') continue;

  const title = (product.title || product.description || 'No Title').substring(0, 100);
  const description = (product.description || title).substring(0, 200);
  const shopCount = product.shopCount || 0;
  let plpUrl = product.plpUrl || '';

  if (plpUrl && !plpUrl.startsWith('http')) {
    plpUrl = 'https://www.beslist.nl' + plpUrl;
  }

  if (plpUrl && description && shopCount >= 2) {
    products.push({
      title,
      url: plpUrl,
      listviewContent: description
    });
  }
}

// Limit to 30 for prompt
const limitedProducts = products.slice(0, 30);

return {
  json: {
    url,
    h1_title,
    products: limitedProducts,
    products_count: limitedProducts.length
  }
};

// Post-process GPT output: fix truncated URLs, sanitize, validate links
// Based on gpt_service.py:fix_truncated_urls() and scraper_service.py:sanitize_content()

const content = $json.message?.content || '';
const products = $('extract_products').item.json.products || [];
const url = $('extract_products').item.json.url;

// 1. Fix truncated URLs (GPT sometimes shortens /p/name/maincat/pimId/ to /p/name/)
const slugToUrl = {};
for (const p of products) {
  if (p.url && p.url.includes('/p/')) {
    const m = p.url.match(/\/p\/([^/]+)\//);
    if (m) slugToUrl[m[1]] = p.url;
  }
}

let fixed = content.replace(
  /href="(https:\/\/www\.beslist\.nl\/p\/[^"]+)"/g,
  (full, href) => {
    const truncMatch = href.match(/^https:\/\/www\.beslist\.nl\/p\/([^/]+)\/?$/);
    if (truncMatch && slugToUrl[truncMatch[1]]) {
      return `href="${slugToUrl[truncMatch[1]]}"`;
    }
    return full;
  }
);

// 2. Sanitize content for SQL (escape single quotes, decode HTML entities)
const sanitized = fixed
  .replace(/'/g, "''")
  .replace(/&amp;/g, '&')
  .replace(/&quot;/g, '"')
  .replace(/&apos;/g, "'")
  .replace(/&#039;/g, "'")
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&nbsp;/g, ' ')
  .replace(/&euro;/g, '\u20AC')
  .replace(/&copy;/g, '\u00A9')
  .replace(/&trade;/g, '\u2122');

// 3. Check if content has valid product links
const hasValidLinks = sanitized.includes('<a href="/p/') ||
                      sanitized.includes('<a href="https://www.beslist.nl/p/');

return {
  json: {
    url,
    sanitized_content: sanitized,
    has_valid_links: hasValidLinks
  }
};
